     3	import { useState, useEffect, useCallback, useMemo } from "react";
     4	import type { AppData, CalendarEvent, Pomodoro } from "./types";
     5	import {
     6	  loadAll,
     7	  saveAll,
     8	} from "./storage";
     9	import { triggerSync, fetchServerData } from "./sync";
    10	import { mergeData, withoutTombstones } from "./merge";
    11	
    12	/**
    13	 * 应用数据管理 Hook
    14	 *
    15	 * 封装了 localStorage 读写 + 服务端同步触发
    16	 * 所有数据变更统一走这里，确保同步一致性
    17	 */
    18	export function useAppData() {
    19	  const [data, setData] = useState<AppData>(() => ({
    20	    events: [],
    21	    pomodoros: [],
    22	  }));
    23	  const [loaded, setLoaded] = useState(false);
    24	
    25	  // 初始化：从 localStorage 加载，尝试从服务端合并
    26	  useEffect(() => {
    27	    const local = loadAll();
    28	    setData(local);
    29	    setLoaded(true);
    30	
    31	    // 后台尝试拉取服务端数据合并
    32	    fetchServerData().then((server) => {
    33	      if (!server) return;
    34	
    35	      // 合并前提取客户端墓碑，避免被 mergeData 滤掉
    36	      const clientTombstones = {
    37	        events: local.events.filter((e) => e._deleted),
    38	        pomodoros: local.pomodoros.filter((p) => p._deleted),
    39	      };
    40	
    41	      const merged = mergeData(local, server);
    42	
    43	      // 将客户端墓碑追加回去，确保删除不丢失
    44	      const withTombstones: AppData = {
    45	        events: [...merged.events, ...clientTombstones.events],
    46	        pomodoros: [...merged.pomodoros, ...clientTombstones.pomodoros],
    47	      };
    48	
    49	      // 只在有差异时更新
    50	      if (JSON.stringify(withTombstones) !== JSON.stringify(local)) {
    51	        setData(withTombstones);
    52	        saveAll(withTombstones);
    53	      }
    54	    });
    55	  }, []);
    56	
    57	  // 持久化 + 同步
    58	  const persist = useCallback((newData: AppData) => {
    59	    setData(newData);
    60	    saveAll(newData);
    61	    triggerSync(newData);
    62	  }, []);
    63	
    64	  // ===== 事件操作 =====
    65	  const addEvent = useCallback(
    66	    (event: CalendarEvent) => {
    67	      const now = new Date().toISOString();
    68	      const newData = { ...data, events: [...data.events, { ...event, updatedAt: now }] };
    69	      persist(newData);
    70	    },
    71	    [data, persist]
    72	  );
    73	
    74	  const updateEvent = useCallback(
    75	    (updated: CalendarEvent) => {
    76	      const now = new Date().toISOString();
    77	      const newData = {
    78	        ...data,
    79	        events: data.events.map((e) =>
    80	          e.id === updated.id ? { ...updated, updatedAt: now } : e
    81	        ),
    82	      };
    83	      persist(newData);
    84	    },
    85	    [data, persist]
    86	  );
    87	
    88	  const deleteEvent = useCallback(
    89	    (id: string) => {
    90	      const now = new Date().toISOString();
    91	      const newData = {
    92	        ...data,
    93	        events: data.events.map((e) =>
    94	          e.id === id ? { ...e, _deleted: true, updatedAt: now } : e
    95	        ),
    96	      };
    97	      persist(newData);
    98	    },
    99	    [data, persist]
   100	  );
   101	
   102	  // ===== 番茄钟操作 =====
   103	  const addPomodoro = useCallback(
   104	    (pomodoro: Pomodoro) => {
   105	      const now = new Date().toISOString();
   106	      const newData = {
   107	        ...data,
   108	        pomodoros: [{ ...pomodoro, updatedAt: now }, ...data.pomodoros],
   109	      };
   110	      persist(newData);
   111	    },
   112	    [data, persist]
   113	  );
   114	
   115	  const displayData = useMemo(
   116	    () => ({
   117	      events: withoutTombstones(data.events),
   118	      pomodoros: withoutTombstones(data.pomodoros),
   119	    }),
   120	    [data]
   121	  );
   122	
   123	  return {
   124	    data: displayData,
   125	    loaded,
   126	    addEvent,
   127	    updateEvent,
   128	    deleteEvent,
   129	    addPomodoro,
   130	  };
   131	}

