    18	const AppContext = createContext<AppContextValue | null>(null);
    19	
    20	export function AppProvider({ children }: { children: ReactNode }) {
    21	  const [currentDate, setCurrentDate] = useState(() => new Date());
    22	  const [focusMinutes, setFocusMinutes] = useState(25);
    23	  const [breakMinutes, setBreakMinutes] = useState(5);
    24	
    25	  const goToday = useCallback(() => {
    26	    setCurrentDate(new Date());
    27	  }, []);
    28	
    29	  return (
    30	    <AppContext.Provider
    31	      value={{
    32	        currentDate,
    33	        setCurrentDate,
    34	        goToday,
    35	        focusMinutes,
    36	        setFocusMinutes,
    37	        breakMinutes,
    38	        setBreakMinutes,
    39	      }}
    40	    >
    41	      {children}
    42	    </AppContext.Provider>
    43	  );
    44	}
    45	
    46	export function useAppContext(): AppContextValue {
